mapper.select:
select station,datatime,validdate,vti, rain from ${tableName} where validdate >= #{startValidDate} and validdate <=#{endValidDate}
                                        and vti in 
                                                        #{id}
                                                   
                                        and station in 
                                                            #{id}
                                                         order by validdate asc, vti asc

select station,datatime,validdate,vti,tp as rain from ${tableName} where validdate >= #{startValidDate} and validdate <=#{endValidDate}
                                        and hour = #{hour}
                                        and vti in 
                                                        #{id}
                                                   
                                        and station in 
                                                            #{id}
                                                         order by validdate asc, vti asc

select station,datatime,validdate,vti,rain from ${tableName} where validdate >= #{startValidDate} and validdate <=#{endValidDate}
                                 and hour = #{hour}
                                 and vti in 
                                                #{id}
                                            
                                 and station in 
                                                    #{id}
                                                 order by validdate asc

select station,datatime,validdate,vti, tp as rain from ${tableName} where validdate >= #{startValidDate} and validdate <=#{endValidDate}
                                 and hour = #{hour}
                                 and vti in 
                                                #{id}
                                            
                                 and station in 
                                                    #{id}
                                                 order by validdate asc

select * from ${tableName} where datatime = #{dataTime} and rainvti = #{rainVti}
                             and vti in 
                                            #{id}
                                        
                              order by vti

    	select station,datatime,datasource,${fieldsName} from public.grib_check_value_tab where datatime >= #{startValidDate} and datatime <= #{endValidDate} and hour = #{hour}
    														and datasource in 
													                              #{id}
													                          
    														and station in 
												                               #{id}
